// ─────────────────────────────────────────────────────────────────
// BUILD EXPORT — Genere le fichier RIS + fichier Excel pre-screening
// Utilise la bibliotheque xlsx pour generer le .xlsx avec couleurs
// ─────────────────────────────────────────────────────────────────
const XLSX = require('xlsx');
const articles = $input.all().map(i => i.json);

// === Format de sortie choisi par user (output_format) ===
// Recupere depuis le premier article (propage par orchestrator > Parse Query)
const userOutputFormat = ((articles[0] && articles[0].output_format) || 'ris').toLowerCase();

// === Helper buildNbib() format MEDLINE ===
function buildNbib(arts) {
  function fmt(tag, value) {
    if (!value && value !== 0) return '';
    const v = String(value).replace(/\r/g, '').replace(/\n/g, ' ').trim();
    return v ? (tag.padEnd(4) + '- ' + v + '\n') : '';
  }
  return arts.map(a => {
    let out = '';
    if (a.pmid) out += fmt('PMID', a.pmid);
    out += fmt('OWN', 'NLM');
    out += fmt('STAT', 'MEDLINE');
    out += fmt('PT', 'Journal Article');
    out += fmt('TI', a.title);
    if (Array.isArray(a.authors)) {
      for (const au of a.authors) {
        if (!au) continue;
        out += fmt('FAU', au);
        const parts = au.trim().split(/\s+/);
        if (parts.length >= 2) {
          const last = parts[parts.length - 1];
          const initials = parts.slice(0, -1).map(p => p.charAt(0).toUpperCase()).join('');
          out += fmt('AU', last + ' ' + initials);
        } else {
          out += fmt('AU', au);
        }
      }
    }
    if (a.journal) { out += fmt('JT', a.journal); out += fmt('TA', a.journal); }
    if (a.volume) out += fmt('VI', a.volume);
    if (a.issue) out += fmt('IP', a.issue);
    if (a.pages) out += fmt('PG', a.pages);
    if (a.year) out += fmt('DP', a.year);
    if (a.abstract) out += fmt('AB', a.abstract);
    if (a.doi) { out += fmt('AID', a.doi + ' [doi]'); out += fmt('LID', a.doi + ' [doi]'); }
    if (a._source) out += fmt('SO', '[source:' + a._source + ']');
    return out + '\n';
  }).join('');
}

// === Helper buildBibTeX() format BibTeX/LaTeX ===
function buildBibTeX(arts) {
  function escapeBib(s) {
    if (!s) return '';
    return String(s).replace(/\\/g, '\\textbackslash{}').replace(/[{}]/g, '')
      .replace(/[#$%&_]/g, '\\$&').replace(/[\r\n]+/g, ' ').trim();
  }
  return arts.map((a, i) => {
    let surname = '';
    if (Array.isArray(a.authors) && a.authors.length > 0) {
      const parts = String(a.authors[0]).trim().split(/\s+/);
      surname = (parts[parts.length - 1] || '').replace(/[^a-zA-Z]/g, '');
    }
    const year = (a.year || 'NA').toString().match(/\d{4}/);
    const key = (surname || 'anon') + (year ? year[0] : 'NA') + '_' + (i + 1);
    const authors = Array.isArray(a.authors) ? a.authors.map(escapeBib).join(' and ') : escapeBib(a.authors || '');
    let e = '@article{' + key + ',\n';
    if (a.title)   e += '  title = {' + escapeBib(a.title) + '},\n';
    if (authors)   e += '  author = {' + authors + '},\n';
    if (a.journal) e += '  journal = {' + escapeBib(a.journal) + '},\n';
    if (a.year)    e += '  year = {' + escapeBib(a.year) + '},\n';
    if (a.volume)  e += '  volume = {' + escapeBib(a.volume) + '},\n';
    if (a.issue)   e += '  number = {' + escapeBib(a.issue) + '},\n';
    if (a.pages)   e += '  pages = {' + escapeBib(a.pages).replace('-', '--') + '},\n';
    if (a.doi)     e += '  doi = {' + escapeBib(a.doi) + '},\n';
    if (a.abstract) e += '  abstract = {' + escapeBib(a.abstract).substring(0, 2000) + '},\n';
    if (a.pmid)    e += '  pmid = {' + escapeBib(a.pmid) + '},\n';
    e += '}\n\n';
    return e;
  }).join('');
}



// ─── 1. GENERER LE FICHIER RIS ─────────────────────────────────
let ris = '';

articles.forEach(a => {
  const title = (a.title || '').replace(/\n/g, ' ');
  const doi = a.doi || '';
  const year = a.year || '';
  const journal = (a.journal || '').replace(/\n/g, ' ');
  const abstract = (a.abstract || '').replace(/\n/g, ' ').substring(0, 2000);
  const authors = Array.isArray(a.authors) ? a.authors : [];
  const score = a.score !== undefined ? a.score : '';
  const cluster = a.cluster !== undefined ? a.cluster : '';
  const cluster_label = a.cluster_label || '';
  const decision = a.screening_decision || '';
  const reason = a.screening_reason || '';
  const pdf_url = a.pdf_url || '';
  const source = a.source || '';

  ris += 'TY  - JOUR\n';
  ris += 'TI  - ' + title + '\n';
  authors.forEach(au => { ris += 'AU  - ' + au + '\n'; });
  if (year) ris += 'PY  - ' + year + '\n';
  if (journal) ris += 'JO  - ' + journal + '\n';
  if (doi) ris += 'DO  - ' + doi + '\n';
  if (abstract) ris += 'AB  - ' + abstract + '\n';
  if (source) ris += 'DB  - ' + source + '\n';
  if (score !== '') ris += 'N1  - relevance_score:' + score + '\n';
  if (cluster !== '') ris += 'N1  - cluster:' + cluster + (cluster_label ? ' (' + cluster_label + ')' : '') + '\n';
  if (decision) ris += 'N1  - screening:' + decision + (reason ? ' — ' + reason : '') + '\n';
  if (pdf_url) ris += 'UR  - ' + pdf_url + '\n';
  ris += 'ER  - \n\n';
});

// ─── 2. GENERER LE FICHIER EXCEL PRE-SCREENING ─────────────────
// Trier: Include en premier, puis Maybe, puis Exclude
const sortOrder = { 'Include': 0, 'Maybe': 1, 'Exclude': 2 };
const sorted = [...articles].sort((a, b) => {
  const orderA = sortOrder[a.screening_decision] !== undefined ? sortOrder[a.screening_decision] : 1;
  const orderB = sortOrder[b.screening_decision] !== undefined ? sortOrder[b.screening_decision] : 1;
  if (orderA !== orderB) return orderA - orderB;
  return (b.score || 0) - (a.score || 0);
});

// Construire les donnees pour le spreadsheet
const wsData = [
  ['Titre', 'Auteurs', 'Annee', 'Journal', 'DOI', 'URL Article', 'Source', 'Abstract', 'Score Pertinence', 'Critere Ranking', 'Decision Pre-screening', 'Couleur', 'Justification', 'Cluster', 'PDF URL', 'Open Access']
];

sorted.forEach(a => {
  const colorLabel = {
    'Include': 'VERT - Inclusion probable',
    'Maybe': 'ORANGE - Unclear',
    'Exclude': 'ROUGE - Non-inclusion probable'
  };
  wsData.push([
    a.title || '',
    Array.isArray(a.authors) ? a.authors.join('; ') : '',
    a.year || '',
    a.journal || '',
    a.doi || '',
    a.url || (a.doi ? ('https://doi.org/' + a.doi) : ''),
    a.source || '',
    (a.abstract || '').substring(0, 1000),
    a.score !== undefined ? a.score : 50,
    a.score_reason || '',
    a.screening_decision || 'Maybe',
    colorLabel[a.screening_decision] || 'ORANGE - Unclear',
    a.screening_reason || '',
    a.cluster_label || '',
    a.pdf_url || '',
    a.is_oa ? 'Oui' : 'Non'
  ]);
});

const wb = XLSX.utils.book_new();
const ws = XLSX.utils.aoa_to_sheet(wsData);

// Set column widths
ws['!cols'] = [
  { wch: 50 },  // Titre
  { wch: 30 },  // Auteurs
  { wch: 6 },   // Annee
  { wch: 25 },  // Journal
  { wch: 25 },  // DOI
  { wch: 40 },  // URL Article
  { wch: 12 },  // Source
  { wch: 60 },  // Abstract
  { wch: 8 },   // Score
  { wch: 40 },  // Critere Ranking
  { wch: 15 },  // Decision
  { wch: 28 },  // Couleur
  { wch: 50 },  // Justification
  { wch: 20 },  // Cluster
  { wch: 40 },  // PDF URL
  { wch: 8 }    // Open Access
];

// Auto-filter on all columns
ws['!autofilter'] = { ref: XLSX.utils.encode_range({
  s: { r: 0, c: 0 },
  e: { r: wsData.length - 1, c: wsData[0].length - 1 }
})};

// Apply cell colors for the Decision column (column K = index 10)
for (let row = 1; row < wsData.length; row++) {
  const cellRef = XLSX.utils.encode_cell({ r: row, c: 10 });
  const cell = ws[cellRef];
  if (cell) {
    const decision = wsData[row][10];
    let bgColor = 'FFA500'; // orange default
    if (decision === 'Include') bgColor = '00B050'; // green
    else if (decision === 'Exclude') bgColor = 'FF0000'; // red
    cell.s = {
      fill: { fgColor: { rgb: bgColor } },
      font: { color: { rgb: 'FFFFFF' }, bold: true }
    };
  }

  // Also color the Couleur column (column L = index 11)
  const colorCellRef = XLSX.utils.encode_cell({ r: row, c: 11 });
  const colorCell = ws[colorCellRef];
  if (colorCell) {
    const decision = wsData[row][10];
    let bgColor = 'FFA500';
    if (decision === 'Include') bgColor = '00B050';
    else if (decision === 'Exclude') bgColor = 'FF0000';
    colorCell.s = {
      fill: { fgColor: { rgb: bgColor } },
      font: { color: { rgb: 'FFFFFF' }, bold: true }
    };
  }
}

// Style header row
for (let col = 0; col < wsData[0].length; col++) {
  const cellRef = XLSX.utils.encode_cell({ r: 0, c: col });
  const cell = ws[cellRef];
  if (cell) {
    cell.s = {
      fill: { fgColor: { rgb: '4472C4' } },
      font: { color: { rgb: 'FFFFFF' }, bold: true },
      alignment: { horizontal: 'center' }
    };
  }
}

XLSX.utils.book_append_sheet(wb, ws, 'Pre-screening');

// Add a summary sheet
const summaryData = [
  ['Statistiques du Pre-screening'],
  [],
  ['Total articles', articles.length],
  ['Inclusion probable (vert)', articles.filter(a => a.screening_decision === 'Include').length],
  ['Unclear (orange)', articles.filter(a => a.screening_decision === 'Maybe').length],
  ['Non-inclusion probable (rouge)', articles.filter(a => a.screening_decision === 'Exclude').length],
  ['PDFs disponibles', articles.filter(a => a.pdf_url).length],
  [],
  ['Sources'],
  ...([...new Set(articles.map(a => a.source).filter(Boolean))].map(s => [
    s, articles.filter(a => a.source === s).length
  ])),
  [],
  ['Clusters thematiques'],
  ...([...new Set(articles.map(a => a.cluster_label).filter(Boolean))].map(label => [
    label, articles.filter(a => a.cluster_label === label).length
  ]))
];

const wsSummary = XLSX.utils.aoa_to_sheet(summaryData);
wsSummary['!cols'] = [{ wch: 35 }, { wch: 10 }];
XLSX.utils.book_append_sheet(wb, wsSummary, 'Statistiques');

// Generate XLSX as base64
const xlsxBuffer = XLSX.write(wb, { type: 'buffer', bookType: 'xlsx' });
const xlsx_base64 = Buffer.from(xlsxBuffer).toString('base64');

// ─── 3. STATISTIQUES ───────────────────────────────────────────
const stats = {
  total: articles.length,
  included: articles.filter(a => a.screening_decision === 'Include').length,
  excluded: articles.filter(a => a.screening_decision === 'Exclude').length,
  maybe: articles.filter(a => a.screening_decision === 'Maybe').length,
  with_pdf: articles.filter(a => a.pdf_url).length,
  sources: [...new Set(articles.map(a => a.source).filter(Boolean))],
  clusters: [...new Set(articles.map(a => a.cluster_label).filter(Boolean))],
  total_before_dedup: (articles[0] && articles[0]._total_before_dedup) || articles.length,
  duplicates_removed: (articles[0] && articles[0]._duplicates_removed) || 0
};

console.log('Export: ' + articles.length + ' articles, RIS: ' + ris.length + ' chars, XLSX: ' + xlsx_base64.length + ' bytes base64');
console.log('Stats: included=' + stats.included + ' excluded=' + stats.excluded + ' maybe=' + stats.maybe);


// === Sauvegarder le format choisi par user (en plus du RIS qui reste toujours) ===
// Note : on suppose ici qu'on a deja un object resultat genere par le code existant.
// Si pas dispo, on log juste un warning et continue.
try {
  if (userOutputFormat === 'nbib' || userOutputFormat === 'bib') {
    const fs = require('fs');
    const outputFolder = (articles[0] && articles[0].output_folder) || '/desktop';
    if (userOutputFormat === 'nbib') {
      const nbibContent = buildNbib(articles);
      const nbibPath = outputFolder + '/references.nbib';
      fs.writeFileSync(nbibPath, nbibContent, 'utf-8');
      console.log('[Export] +references.nbib (' + nbibContent.length + ' bytes)');
    }
    if (userOutputFormat === 'bib') {
      const bibContent = buildBibTeX(articles);
      const bibPath = outputFolder + '/references.bib';
      fs.writeFileSync(bibPath, bibContent, 'utf-8');
      console.log('[Export] +references.bib (' + bibContent.length + ' bytes)');
    }
  }
} catch (e) {
  console.log('[Export] Erreur generation format choisi : ' + e.message);
}

return [{
  json: {
    ris,
    xlsx_base64,
    articles,
    stats,
    output_folder: (articles[0] && articles[0].output_folder) || ''
  }
}];
